const execution_id = $("Start").first().json.execution_id;
const source_execution_id = $("Start").first().json.source_execution_id ?? null;
const client_id_filter = $("Start").first().json.client_id ?? null;

const pickPlain = (prop) => {
  if (!prop) return null;
  if (prop.title?.length) return prop.title[0].plain_text?.trim() || null;
  if (prop.rich_text?.length) return prop.rich_text[0].plain_text?.trim() || null;
  return null;
};

const pickNumber = (prop) => {
  const value = prop?.number;
  return value === null || value === undefined ? null : Number(value);
};

const pickScalar = (prop) => {
  if (!prop) return null;
  if (prop.number !== undefined && prop.number !== null) return prop.number;
  if (prop.rich_text?.length) return prop.rich_text[0].plain_text?.trim() || null;
  if (prop.title?.length) return prop.title[0].plain_text?.trim() || null;
  if (prop.rollup) {
    if (prop.rollup.type === "number") return prop.rollup.number;
    if (prop.rollup.type === "date") return prop.rollup.date?.start || null;
    if (prop.rollup.type === "array") {
      const first = prop.rollup.array?.[0];
      if (!first) return null;
      if (first.type === "number") return first.number;
      if (first.type === "rich_text") return first.rich_text?.[0]?.plain_text?.trim() || null;
      if (first.type === "title") return first.title?.[0]?.plain_text?.trim() || null;
      if (first.type === "formula") {
        if (first.formula?.type === "number") return first.formula.number;
        if (first.formula?.type === "string") return first.formula.string?.trim() || null;
      }
    }
  }
  if (prop.formula) {
    if (prop.formula.type === "number") return prop.formula.number;
    if (prop.formula.type === "string") return prop.formula.string?.trim() || null;
  }
  return null;
};

const pickIdString = (prop) => {
  const value = pickScalar(prop);
  if (value === null || value === undefined) return null;
  const normalized = String(value).trim();
  if (!normalized) return null;
  return normalized.replace(/[^\d]/g, "") || normalized;
};

return $input.all().flatMap((item) => {
  const props = item.json.properties || {};

  const ad_id_google = pickIdString(props["ad_id_google"]);
  const ad_id_meta = pickIdString(props["ad_id_meta"]);
  const customer_id_google = pickIdString(props["customer_id_google"]);
  const meta_account_id = pickIdString(props["meta_account_id"]);
  const adset_id_google = pickIdString(props["adset_id_google"]);
  const adset_id_meta = pickIdString(props["adset_id_meta"]);
  const client_slug = pickPlain(props["Sigla Cliente"]);

  if (client_id_filter && client_slug && client_id_filter !== client_slug) {
    return [];
  }

  const platform = ad_id_google ? "google_ads" : (ad_id_meta ? "meta_ads" : null);
  if (!platform) return [];

  return [{
    json: {
      execution_id,
      source_execution_id,
      entity_type: "ad",
      notion_page_id: item.json.id,
      nome: pickPlain(props["Nome"]),
      campaign_id: pickPlain(props["campaign_id"]),
      platform,
      ad_id_google,
      ad_id_meta,
      customer_id_google,
      meta_account_id,
      adset_id_google,
      adset_id_meta,
      cpa_alvo: pickNumber(props["CPA Alvo"]),
      criativo_base: {
        ad_criativo: props["AD_Criativo"]?.select?.name || null,
        ad_formato: (props["AD_Formato"]?.multi_select || []).map((x) => x.name),
        hook: pickPlain(props["Hook"]),
        origem_criativo: props["Origem Criativo"]?.select?.name || null,
        url_criativo: props["URL Criativo"]?.url || null
      }
    }
  }];
});

