const source = $input.first().json;
const fromGoogle = source.results !== undefined || source.fieldMask !== undefined || source.queryResourceConsumption !== undefined;

let impressions = 0;
let clicks = 0;
let cost_brl = 0;
let conversions = 0;
let revenue = 0;
let frequency = null;
let base;

if (fromGoogle) {
  base = $("If IDs Google").first().json;
  const metrics = source.results?.[0]?.metrics || {};
  impressions = Number(metrics.impressions || 0);
  clicks = Number(metrics.clicks || 0);
  cost_brl = Number(metrics.costMicros || 0) / 1000000;
  conversions = Number(metrics.conversions || 0);
  revenue = Number(metrics.conversionsValue || 0);
} else {
  base = $("If IDs Meta").first().json;
  const payload = source.data?.[0] || {};
  impressions = Number(payload.impressions || 0);
  clicks = Number(payload.clicks || 0);
  cost_brl = Number(payload.spend || 0);
  frequency = payload.frequency === undefined ? null : Number(payload.frequency || 0);
  const actionMap = Object.fromEntries((payload.actions || []).map((entry) => [entry.action_type, Number(entry.value || 0)]));
  const valueMap = Object.fromEntries((payload.action_values || []).map((entry) => [entry.action_type, Number(entry.value || 0)]));
  conversions = actionMap['offsite_conversion.fb_pixel_purchase'] || actionMap['purchase'] || actionMap['lead'] || actionMap['omni_purchase'] || 0;
  revenue = valueMap['offsite_conversion.fb_pixel_purchase'] || valueMap['purchase'] || valueMap['omni_purchase'] || 0;
}

return [{
  json: {
    ...base,
    metrics: {
      impressions,
      clicks,
      cost_brl: Number(cost_brl.toFixed(2)),
      conversions,
      revenue: Number(revenue.toFixed(2)),
      ctr: impressions > 0 ? Number((clicks / impressions).toFixed(6)) : 0,
      cpc: clicks > 0 ? Number((cost_brl / clicks).toFixed(2)) : 0,
      cpa: conversions > 0 ? Number((cost_brl / conversions).toFixed(2)) : 0,
      roas: cost_brl > 0 ? Number((revenue / cost_brl).toFixed(4)) : 0,
      conversion_rate: clicks > 0 ? Number((conversions / clicks).toFixed(6)) : 0,
      frequency
    }
  }
}];

