const cpaAlvo = Number($json.cpa_alvo || 0);

let status = 'Sem dados';
let prioridade = 'Baixa';
let tendencia = 'Sem dados';
let emoji = 'NO_DATA';
let diagnostico = 'Sem volume suficiente para analise.';
let score = 0;

if (d.impressions >= 100 && d.clicks >= 5) {
